  path: string,
  init: RequestInit,
): Promise<{ ok: boolean; status: number; body: T | null }> {
  const response = await fetch(`${apiBaseUrl}${path}`, {
    ...init,
    credentials: "include",
    headers: {
      "Content-Type": "application/json",
      ...(init.headers ?? {}),
    },
