  function updateViewState(nextViewState: TodoViewState) {
    const nextSearchParams = buildTodoSearchParams(nextViewState);
    const nextQueryString = nextSearchParams.toString();
    const nextUrl = nextQueryString ? `${pathname}?${nextQueryString}` : pathname;

    router.replace(nextUrl, { scroll: false });
  }

  async function handleAddTodo(values: AddTodoFormValues): Promise<boolean> {
    setActiveAction("create");

    try {
      const response = await request<TodoRecord>("/api/todos", {
        method: "POST",
        body: JSON.stringify(values),
      });

      if (response.status === 401) {
        setIsAuthenticated(false);
        setTodos([]);
        setStatus({
          tone: "neutral",
          message: "Sign in to add todos for your account.",
        });
        return false;
      }

      if (!response.ok || !response.body) {
        setStatus({
          tone: "error",
          message: getResponseMessage(response.body, "Unable to add todo."),
        });
        return false;
      }

      setIsAuthenticated(true);
      await loadTodos({
        successStatus: {
          tone: "success",
          message: "Todo added.",
        },
      });

      return true;
    } catch {
      setStatus({
        tone: "error",
        message: "Unable to reach the todo API.",
      });
      return false;
    } finally {
      setActiveAction(null);
    }
  }

  async function handleToggleTodo(todo: TodoRecord) {
    setActiveAction(`toggle:${todo.id}`);

    try {
      const response = await request<TodoRecord>(`/api/todos/${todo.id}`, {
        method: "PATCH",
        body: JSON.stringify({
          completed: !todo.completed,
        }),
      });

      if (response.status === 401) {
        setIsAuthenticated(false);
        setTodos([]);
        setStatus({
          tone: "neutral",
          message: "Sign in to update todos for your account.",
        });
        return;
      }

      if (!response.ok || !response.body) {
        setStatus({
          tone: "error",
          message: getResponseMessage(response.body, "Unable to update todo."),
        });
        return;
      }

      await loadTodos({
        successStatus: {
          tone: "success",
          message: response.body.completed
            ? "Todo marked complete."
            : "Todo marked pending.",
        },
      });
    } catch {
      setStatus({
        tone: "error",
        message: "Unable to reach the todo API.",
      });
    } finally {
      setActiveAction(null);
    }
  }

  async function handleSaveDueDate(todo: TodoRecord, dueDate: string | null) {
    setActiveAction(`dueDate:${todo.id}`);

