};

type NormalizedCreateTodoInput = {
  title: string;
  description: string | null;
  status: WorkItemStatus;
  dueDate: string | null;
  priority: TodoPriority;
};

export class TodoValidationError extends Error {
  constructor(message: string) {
    super(message);
