  const sortOrder = options.order ?? "desc";
  const orderDirection = sortOrder.toUpperCase();
  const orderByClause =
    sortField === "priority"
      ? `
          CASE priority
            WHEN 'low' THEN 1
            WHEN 'medium' THEN 2
            WHEN 'high' THEN 3
          END ${orderDirection},
          created_at DESC,
          id DESC
        `
      : `
          created_at ${orderDirection},
          id DESC
        `;

